function calcSunTimes(date, latitude, longitude) {
    const doy = dayOfYear(date);
    const decl = 23.45 * Math.sin((Math.PI / 180) * (360 / 365) * (doy - 81));
    const declRad = decl * Math.PI / 180;
    const latRad = latitude * Math.PI / 180;
    let cosHa = -Math.tan(latRad) * Math.tan(declRad);
    cosHa = Math.max(-1, Math.min(1, cosHa));
    const haDeg = Math.acos(cosHa) * 180 / Math.PI;
    const noonH = 12 - longitude / 15;
    let sunriseH = Math.max(0, Math.min(23.99, noonH - haDeg / 15));
    let sunsetH = Math.max(0, Math.min(23.99, noonH + haDeg / 15));
    function fmt(h) {
        const hh = Math.floor(h);
        const mm = Math.floor((h - hh) * 60);
        return String(hh).padStart(2, '0') + ':' + String(mm).padStart(2, '0');
    }
    return [fmt(sunriseH), fmt(sunsetH), sunriseH, sunsetH];
}

const EVENT_DAY_SCHEDULE = [
    { hour: 9, duration: 30, type: 'ACCIDENT', severity: 'MEDIUM', severity_num: 2 },
    { hour: 14, duration: 45, type: 'EMERGENCY', severity: 'HIGH', severity_num: 3 },
    { hour: 20, duration: 20, type: 'EVENT', severity: 'LOW', severity_num: 1 }
];

function dayOrdinal(date) {
    // Days since 0001-01-01 (Python date.toordinal proxy)
    const epoch = Date.UTC(1, 0, 1);
    return Math.floor((Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate()) - epoch) / 86400000) + 1;
}

function generateEvent(payload) {
    const baseSeed = (typeof payload.base_seed === 'number') ? payload.base_seed : 12345;
    const entityId = payload.entity_id || 'event-default';
    const tsMs = (typeof payload.timestamp_ms === 'number') ? payload.timestamp_ms : 0;
    const isoTs = payload.timestamp || new Date(tsMs).toISOString();
    const cityId = payload.city_id || 'city-berlin';
    const zoneId = payload.zone_id || 'zone-001';
    const mode = payload.mode || 'normal';
    const date = new Date(isoTs);
    if (mode !== 'event') {
        return {
            city_id: cityId, zone_id: zoneId, timestamp: isoTs,
            event_type: 'EVENT', severity: 'LOW', severity_num: 1, active: false
        };
    }
    const daySeed = dayOrdinal(date);
    const rng = makeRng(baseSeed, entityId, 'event-day', daySeed);
    const events = EVENT_DAY_SCHEDULE.map(e => {
        const jitter = Math.floor(uniform(rng, -1, 2));
        const hour = Math.max(0, Math.min(23, e.hour + jitter));
        return Object.assign({}, e, { hour });
    });
    const minOfDay = date.getUTCHours() * 60 + date.getUTCMinutes();
    for (const e of events) {
        const start = e.hour * 60;
        const end = start + e.duration;
        if (minOfDay >= start && minOfDay < end) {
            return {
                city_id: cityId, zone_id: zoneId, timestamp: isoTs,
                event_type: e.type, severity: e.severity, severity_num: e.severity_num,
                active: true
            };
        }
    }
    return {
        city_id: cityId, zone_id: zoneId, timestamp: isoTs,
        event_type: 'EVENT', severity: 'LOW', severity_num: 1, active: false
    };
}

msg.payload = generateEvent(msg.payload || {});
return msg;
